package aula_02_operadores;

public class Operadores_Atribuicao {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		int numero1 = 4;
		int numero2 = 4;
		int numero3 = 4;
		int numero4 = 4;
		int numero5 = 4;
		
		System.out.println("Atribuição com soma: " + (numero1 += 2));
		System.out.println("Atribuição com subtração: " + (numero2 -= 2));
		System.out.println("Atribuição com multiplicação: " + (numero3 *= 2));
		System.out.println("Atribuição com divisão: " + (numero1 /= 2));
		System.out.println("Atribuição com módulo: " + (numero1 %= 2));

	}

}
